// Script Continued Below
var ARM_uiAction = Class.create();
ARM_uiAction.prototype = {
    initialize: function() {
    },

	uiAction_ARM_Accept: function(reportActivity) {
		// TODO - multilanguage
		reportActivity.status = 'accepted';
		reportActivity.update();
	},

	uiAction_ARM_Complete: function(reportActivity) {
		// TODO - multilanguage
		reportActivity.status = 'completed';
		reportActivity.update();
	},

	uiAction_ARM_Promote: function(reportActivity) {
		var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		grOU.addQuery('sys_id', reportActivity.assignee_ou);
		grOU.query();
		if(grOU.next()){
			//reportActivity.previous_ou = reportActivity.assignee_ou;
			reportActivity.assignee_ou = grOU.parent;
			// TODO - multilanguage
			reportActivity.status = 'promoted';
		}
		reportActivity.update();
	},

	uiAction_ARM_Return: function(reportActivity) {
		var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		grOU.addQuery('sys_id', reportActivity.assignee_ou);
		grOU.query();
		if(grOU.next()){
			//reportActivity.previous_ou = reportActivity.assignee_ou;
			//reportActivity.assignee_ou = grOU.parent;
			reportActivity.status = 'returned';
		}
		reportActivity.update();
	},

	uiAction_ARM_Submit: function(reportActivity) {
		// TODO - multilanguage
		reportActivity.status = 'submitted';
		reportActivity.update();
	},

    type: 'ARM_uiAction'
};
